<template>
  <div class="verify-code-container" @click="refreshCode">
    <canvas ref="verifyCanvas" :width="width" :height="height"></canvas>
  </div>
</template>

<script>
export default {
  name: 'VerifyCode',
  
  props: {
    width: {
      type: Number,
      default: 120
    },
    height: {
      type: Number,
      default: 40
    },
    length: {
      type: Number,
      default: 4
    }
  },
  
  data() {
    return {
      code: ''
    }
  },
  
  mounted() {
    this.drawCode()
  },
  
  methods: {
    // 生成随机颜色
    randomColor(min, max) {
      const r = Math.floor(Math.random() * (max - min) + min)
      const g = Math.floor(Math.random() * (max - min) + min)
      const b = Math.floor(Math.random() * (max - min) + min)
      return `rgb(${r},${g},${b})`
    },
    
    // 生成随机验证码
    generateCode() {
      const chars = 'ABCDEFGHJKMNPQRSTWXYZabcdefhkmnpqrstwxyz23456789'
      let code = ''
      for (let i = 0; i < this.length; i++) {
        code += chars.charAt(Math.floor(Math.random() * chars.length))
      }
      return code
    },
    
    // 绘制验证码
    drawCode() {
      const canvas = this.$refs.verifyCanvas
      const ctx = canvas.getContext('2d')
      
      // 生成验证码
      this.code = this.generateCode()
      
      // 绘制背景
      ctx.fillStyle = this.randomColor(200, 240)
      ctx.fillRect(0, 0, this.width, this.height)
      
      // 绘制干扰线
      for (let i = 0; i < 5; i++) {
        ctx.strokeStyle = this.randomColor(100, 200)
        ctx.beginPath()
        ctx.moveTo(Math.random() * this.width, Math.random() * this.height)
        ctx.lineTo(Math.random() * this.width, Math.random() * this.height)
        ctx.stroke()
      }
      
      // 绘制干扰点
      for (let i = 0; i < 30; i++) {
        ctx.fillStyle = this.randomColor(0, 255)
        ctx.beginPath()
        ctx.arc(Math.random() * this.width, Math.random() * this.height, 1, 0, 2 * Math.PI)
        ctx.fill()
      }
      
      // 绘制验证码文字
      const fontSize = this.height * 0.7
      ctx.font = `bold ${fontSize}px Arial`
      ctx.textBaseline = 'middle'
      
      const textWidth = this.width / this.length
      for (let i = 0; i < this.length; i++) {
        const x = textWidth * i + textWidth / 2
        const y = this.height / 2
        
        // 随机旋转角度
        const angle = (Math.random() - 0.5) * 0.4
        
        ctx.save()
        ctx.translate(x, y)
        ctx.rotate(angle)
        ctx.fillStyle = this.randomColor(50, 160)
        ctx.fillText(this.code[i], -fontSize / 3, 0)
        ctx.restore()
      }
    },
    
    // 刷新验证码
    refreshCode() {
      this.drawCode()
    },
    
    // 验证输入的验证码是否正确
    validate(inputCode) {
      return inputCode.toLowerCase() === this.code.toLowerCase()
    }
  }
}
</script>

<style scoped>
.verify-code-container {
  cursor: pointer;
  border-radius: 4px;
  overflow: hidden;
  transition: all 0.3s;
}

.verify-code-container:hover {
  box-shadow: 0 0 8px rgba(0, 0, 0, 0.2);
}
</style>
